                    is_add = 1
                }
            }

            # Check for - ([45])
            もし op_len が 1 ならば、{
                もし op[0] が 45 ならば、{
                    is_sub = 1
                }
            }

            もし is_add が 1 ならば、{
                left = vals[i]
                right = vals[和(i, 1)]
                result = 和(left, right)
                vals[i] = result

                # Shift vals and ops
                k = 和(i, 1)
                vals_len = |vals|
                limit = 差(vals_len, 1)
                limit回、くり返す {
                    もし k が 差(vals_len, 1) より小さいならば、{
                        vals[k] = vals[和(k, 1)]
                    }
                    kを増やす
                }

                k = i
                limit回、くり返す {
                    もし k が 差(ops_len, 1) より小さいならば、{
                        ops[k] = ops[和(k, 1)]
                    }
                    kを増やす
                }

                ops_lenを減らす
            }
