                もし is_sub が 1 ならば、{
                    left = vals[i]
                    right = vals[和(i, 1)]
                    result = 差(left, right)
                    vals[i] = result

                    # Shift vals and ops
                    k = 和(i, 1)
                    vals_len = |vals|
